func extractObjectID(obj map[string]any) string {
	for _, key := range []string{"id", "ID", "uuid", "slug", "name"} {
		if v, ok := obj[key]; ok {
			return fmt.Sprintf("%v", v)
		}
	}
	return ""
}

func lookupFieldValue(obj map[string]any, snakeKey string) any {
	if v, ok := obj[snakeKey]; ok {
		return v
	}
	// Try camelCase
	parts := strings.Split(snakeKey, "_")
	for i := 1; i < len(parts); i++ {
		if parts[i] == "" {
			continue
		}
		parts[i] = strings.ToUpper(parts[i][:1]) + parts[i][1:]
	}
	camelKey := strings.Join(parts, "")
	if v, ok := obj[camelKey]; ok {
		return v
	}
	// Handle nested object ID extraction: "team_id" -> obj["team"]["id"]
	if strings.HasSuffix(snakeKey, "_id") {
		parentKey := strings.TrimSuffix(snakeKey, "_id")
		// Try camelCase parent
		parentParts := strings.Split(parentKey, "_")
		for i := 1; i < len(parentParts); i++ {
			if parentParts[i] != "" {
				parentParts[i] = strings.ToUpper(parentParts[i][:1]) + parentParts[i][1:]
			}
		}
		for _, key := range []string{parentKey, strings.Join(parentParts, "")} {
			if nested, ok := obj[key].(map[string]any); ok {
				if id, ok := nested["id"]; ok {
					return id
				}
			}
		}
	}
	return nil
}
