// UpsertBatch inserts or replaces multiple records in a single transaction.
// This is 10-100x faster than individual Upsert calls for bulk operations.
func (s *Store) UpsertBatch(resourceType string, items []json.RawMessage) error {
	tx, err := s.db.Begin()
	if err != nil {
		return fmt.Errorf("starting batch transaction: %w", err)
	}
	defer tx.Rollback()

	for _, item := range items {
		var obj map[string]any
		if err := json.Unmarshal(item, &obj); err != nil {
			continue
		}
		id := fmt.Sprintf("%v", lookupFieldValue(obj, "id"))
		if id == "" || id == "<nil>" {
			continue
		}

		_, err := tx.Exec(
			`INSERT OR REPLACE INTO resources (id, resource_type, data, synced_at, updated_at)
			 VALUES (?, ?, ?, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)`,
			id, resourceType, string(item),
		)
		if err != nil {
			return fmt.Errorf("upserting %s/%s: %w", resourceType, id, err)
		}
	}

	return tx.Commit()
}
// SearchDocuments searches the documents_fts index with optional filters.
func (s *Store) SearchDocuments(query string, limit int) ([]json.RawMessage, error) {
	if limit <= 0 {
		limit = 50
	}
	rows, err := s.db.Query(
		`SELECT t.data FROM documents t
		 JOIN documents_fts ON documents_fts.rowid = t.rowid
		 WHERE documents_fts MATCH ?
		 ORDER BY rank LIMIT ?`,
		query, limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var results []json.RawMessage
	for rows.Next() {
		var data string
		if err := rows.Scan(&data); err != nil {
			return nil, err
		}
		results = append(results, json.RawMessage(data))
	}
	return results, rows.Err()
}
